const order = $json.order || {};
const orderId = order.order_id || "Unknown";
const customerName = order.customer_name || "-";
const channel = order.customer_channel || "-";
const category = order.requested_category || "-";
const weightRange = order.requested_weight_range || "-";
const quantity = order.requested_quantity || "-";
const lineCount = order.line_count || 0;
const reservedPigCount = order.reserved_pig_count || 0;
const orderStatus = order.order_status || "-";
const approvalStatus = order.approval_status || "-";

const message =
`🐷 Order Approval Needed

Order ID: ${orderId}
Customer: ${customerName}
Channel: ${channel}
Category: ${category}
Weight Range: ${weightRange}
Quantity Requested: ${quantity}
Line Count: ${lineCount}
Reserved Pig Count: ${reservedPigCount}
Order Status: ${orderStatus}
Approval Status: ${approvalStatus}

Please reply with:

approve ${orderId}
or
reject ${orderId}`;

return [
  {
    json: {
      order_id: orderId,
      telegram_chat_id: $node["Code - Normalize Orders Sub Agent Payload"].json["telegram_chat_id"],
      message_text: message,
      changed_by: $node["Code - Normalize Orders Sub Agent Payload"].json["changed_by"],
      trigger_source: $node["Code - Normalize Orders Sub Agent Payload"].json["trigger_source"]
    }
  }
];

const msg = $json.message || {};

return [
  {
    json: {
      message_text: (msg.text || "").trim(),
      chat_id: msg.chat?.id,
      user_id: msg.from?.id,
      user_name: msg.from?.first_name || "Unknown",
      message_id: msg.message_id
    }
  }
];

const text = ($json.message_text || "").toLowerCase().trim();

let decision = "";
let order_id = "";

if (text.startsWith("approve ")) {
  decision = "approve";
  order_id = text.replace("approve ", "").toUpperCase();
} else if (text.startsWith("reject ")) {
  decision = "reject";
  order_id = text.replace("reject ", "").toUpperCase();
}

return [
  {
    json: {
      decision,
      order_id,
      chat_id: $json.chat_id,
      user_name: $json.user_name,
      original_text: $json.message_text
    }
  }
];

